import React from "react"

const DealCard = ({ deal }) => {
  const formatPrice = (d) => {
    if (d.price.monthly) return { value: `$${d.price.monthly}`, unit: "/mo" }
    if (d.price.annual) return { value: `$${d.price.annual}`, unit: "/yr" }
    if (d.price.annualPrice) return { value: `$${d.price.annualPrice}`, unit: "/yr" }
    if (d.price.monthlyPerGB) return { value: `$${d.price.monthlyPerGB}`, unit: "/GB/mo" }
    if (d.price.hourly) return { value: `$${d.price.hourly}`, unit: "/hr" }
    if (d.price.inputPer1M) return { value: `$${d.price.inputPer1M}`, unit: "/1M in" }
    return { value: "See site", unit: "" }
  }

  const categoryIcons = {
    vps: "🖥️", gpu: "🎮", domain: "🌐", storage: "💾", serverless: "⚡", "ai-api": "🧠"
  }

  const price = formatPrice(deal)

  return (
    <article style={cardStyle}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.5rem" }}>
        <span style={{ fontSize: "1.2rem" }}>{categoryIcons[deal.category] || "📦"}</span>
        <span style={{
          fontSize: "0.65rem",
          padding: "0.15rem 0.5rem",
          borderRadius: 10,
          background: deal.uncertain ? "#7c2d12" : "#14532d",
          color: deal.uncertain ? "#fb923c" : "#4ade80",
          fontWeight: 600,
        }}>
          {deal.uncertain ? "Verify" : "Verified"}
        </span>
      </div>
      <div style={{ fontSize: "0.7rem", color: "#666", marginBottom: "0.2rem" }}>{deal.provider}</div>
      <h4 style={{ margin: "0 0 0.5rem", color: "#e0e0e0", fontSize: "0.95rem" }}>{deal.name}</h4>
      
      {Object.keys(deal.specs).length > 0 && (
        <div style={{ fontSize: "0.75rem", color: "#888", lineHeight: 1.6, marginBottom: "0.8rem" }}>
          {Object.entries(deal.specs).map(([k, v]) => (
            <div key={k}><span style={{ color: "#555" }}>{k}:</span> {v}</div>
          ))}
        </div>
      )}
      
      <div style={{ display: "flex", alignItems: "baseline", gap: "0.2rem", marginBottom: "0.8rem" }}>
        <span style={{ color: "#10b981", fontWeight: 700, fontSize: "1.3rem" }}>{price.value}</span>
        <span style={{ color: "#666", fontSize: "0.8rem" }}>{price.unit}</span>
        {deal.price.currency !== "USD" && <span style={{ color: "#555", fontSize: "0.7rem", marginLeft: "0.3rem" }}>{deal.price.currency}</span>}
      </div>

      {deal.features && deal.features.length > 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: "0.3rem", marginBottom: "0.8rem" }}>
          {deal.features.slice(0, 4).map((f, i) => (
            <span key={i} style={{ fontSize: "0.65rem", padding: "0.1rem 0.4rem", borderRadius: 4, background: "#1a1a1a", color: "#888" }}>
              {f}
            </span>
          ))}
        </div>
      )}

      <a href={deal.url} target="_blank" rel="noopener noreferrer" style={{
        display: "inline-block", fontSize: "0.75rem", color: "#3b82f6", textDecoration: "none",
      }}>
        Visit {deal.provider} →
      </a>
    </article>
  )
}

const cardStyle = {
  background: "#111",
  border: "1px solid #222",
  borderRadius: 12,
  padding: "1.2rem",
}

export default DealCard
