import React from "react"
import { Link } from "gatsby"
import Layout from "../components/Layout"
import DealCard from "../components/DealCard"
import dealsData from "../../data/deals.json"
import bundlesData from "../../data/bundles.json"

const CategoryPage = () => {
  const { deals } = dealsData
  const { bundles } = bundlesData

  const grouped = {}
  deals.forEach(d => {
    if (!grouped[d.category]) grouped[d.category] = []
    grouped[d.category].push(d)
  })

  const categoryMeta = {
    vps: { icon: "🖥️", label: "VPS & Cloud Compute", desc: "Virtual private servers and cloud instances for hosting, APIs, and orchestration." },
    gpu: { icon: "🎮", label: "GPU Cloud", desc: "GPU instances for AI training, inference, and compute-heavy workloads." },
    domain: { icon: "🌐", label: "Domains", desc: "Domain registration with WHOIS privacy and DNS management." },
    storage: { icon: "💾", label: "Object Storage", desc: "S3-compatible storage for backups, assets, and data lakes." },
    serverless: { icon: "⚡", label: "Serverless & Edge", desc: "Zero-ops compute for frontend, APIs, and edge functions." },
    "ai-api": { icon: "🧠", label: "AI APIs", desc: "LLM and AI model APIs — pay per token, no GPU needed." },
  }

  const relatedBundles = (cat) => bundles.filter(b => b.resources.some(r => deals.find(d => r.dealIds.includes(d.id))?.category === cat))

  return (
    <Layout>
      <h1 style={{ color: "#e0e0e0", fontSize: "1.8rem", marginBottom: "1.5rem" }}>Categories</h1>
      
      {Object.entries(grouped).map(([cat, catDeals]) => {
        const meta = categoryMeta[cat] || { icon: "📦", label: cat, desc: "" }
        const relBundles = relatedBundles(cat)
        return (
          <section key={cat} style={{ marginBottom: "3rem" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "0.8rem", marginBottom: "0.5rem" }}>
              <span style={{ fontSize: "1.5rem" }}>{meta.icon}</span>
              <h2 style={{ color: "#e0e0e0", fontSize: "1.3rem", margin: 0 }}>{meta.label}</h2>
              <span style={{ color: "#555", fontSize: "0.8rem" }}>({catDeals.length} deals)</span>
            </div>
            <p style={{ color: "#888", fontSize: "0.85rem", marginBottom: "1rem" }}>{meta.desc}</p>
            
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "1.5rem" }}>
              {catDeals.map(d => <DealCard key={d.id} deal={d} />)}
            </div>

            {relBundles.length > 0 && (
              <div style={{ marginTop: "1rem", fontSize: "0.85rem", color: "#666" }}>
                Used in: {relBundles.map(b => (
                  <Link key={b.id} to={`/bundle/${b.slug}`} style={{ color: "#3b82f6", textDecoration: "none", marginLeft: "0.5rem" }}>
                    {b.icon} {b.name}
                  </Link>
                ))}
              </div>
            )}
          </section>
        )
      })}
    </Layout>
  )
}

export const Head = () => (
  <>
    <title>Categories — DevBundles</title>
    <meta name="description" content="Browse deals by category: VPS, GPU, domains, storage, serverless, and AI APIs." />
  </>
)

export default CategoryPage
